<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-like Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; font-family: Ubuntu, "Segoe UI", sans-serif; }
  body { overflow: hidden; }

  #desktop {
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, #2c001e 0%, #1a1a1a 60%, #0a0a0a 100%);
    background-size: cover;
    overflow: hidden;
  }

  /* Top bar */
  #topbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(20,20,20,0.85);
    color: #eee;
    display: flex;
    align-items: center;
    padding: 0 12px;
    font-size: 13px;
    z-index: 1000;
    border-bottom: 1px solid #000;
  }
  #topbar .spacer { flex: 1; }

  /* Taskbar / dock */
  #taskbar {
    position: absolute;
    bottom: 0; left: 0; right: 0;
    height: 48px;
    background: rgba(15,15,15,0.9);
    border-top: 1px solid #333;
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 10px;
    z-index: 1000;
  }
  #taskbar button {
    background: #333;
    color: #fff;
    border: 1px solid #555;
    border-radius: 6px;
    padding: 6px 12px;
    cursor: pointer;
    font-size: 13px;
  }
  #taskbar button:hover { background: #444; }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: #2d2d2d;
    border: 1px solid #111;
    border-radius: 8px;
    box-shadow: 0 10px 30px rgba(0,0,0,0.5);
    display: flex;
    flex-direction: column;
    z-index: 100;
  }
  .titlebar {
    height: 32px;
    background: linear-gradient(#3a3a3a, #2a2a2a);
    border-top-left-radius: 8px;
    border-top-right-radius: 8px;
    display: flex;
    align-items: center;
    padding: 0 8px;
    color: #ddd;
    font-size: 13px;
    cursor: move;
    user-select: none;
  }
  .titlebar .title { flex: 1; }
  .win-close {
    background: #c0392b;
    border: none;
    color: #fff;
    width: 20px; height: 20px;
    border-radius: 50%;
    cursor: pointer;
    font-size: 12px;
    line-height: 20px;
    text-align: center;
  }
  .win-close:hover { background: #e74c3c; }
  .window-body {
    flex: 1;
    overflow: auto;
    background: #1e1e1e;
    color: #ddd;
    padding: 8px;
  }

  /* Files */
  #files-path {
    font-family: monospace;
    background: #111;
    padding: 6px 8px;
    border-radius: 4px;
    margin-bottom: 8px;
    color: #9f9;
  }
  #files-up {
    margin-bottom: 8px;
    background: #333;
    color: #fff;
    border: 1px solid #555;
    border-radius: 4px;
    padding: 4px 10px;
    cursor: pointer;
  }
  .fs-item {
    padding: 6px 8px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 14px;
  }
  .fs-item:hover { background: #333; }
  .fs-item.folder::before { content: "📁 "; }
  .fs-item.file::before { content: "📄 "; }

  /* Notepad */
  #tabs {
    display: flex;
    gap: 4px;
    background: #252525;
    padding: 4px;
    overflow-x: auto;
  }
  .tab {
    background: #333;
    color: #ccc;
    padding: 4px 10px;
    border-radius: 4px 4px 0 0;
    cursor: pointer;
    font-size: 13px;
    white-space: nowrap;
  }
  .tab.active { background: #1e1e1e; color: #fff; }
  #new-tab {
    background: #444;
    color: #fff;
    border: none;
    border-radius: 4px;
    padding: 4px 10px;
    cursor: pointer;
    font-size: 13px;
  }
  #editor {
    width: 100%;
    height: 100%;
    border: none;
    resize: none;
    background: #1e1e1e;
    color: #eee;
    padding: 8px;
    font-family: monospace;
    font-size: 14px;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span>Activities</span>
    <span class="spacer"></span>
    <span>Ubuntu 22.04</span>
    <span class="spacer"></span>
    <span>🔋 100% &nbsp; 🔊 &nbsp; ⏰ 12:00</span>
  </div>

  <div id="taskbar">
    <button id="open-files">📁 Files</button>
    <button id="open-notepad">📝 Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window" style="left:60px; top:60px; width:420px; height:320px; display:none;">
    <div class="titlebar">
      <span class="title">Files</span>
      <button class="win-close">×</button>
    </div>
    <div class="window-body">
      <div id="files-path">/</div>
      <button id="files-up">⬆ Up</button>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window" style="left:120px; top:120px; width:420px; height:320px; display:none;">
    <div class="titlebar">
      <span class="title">Notepad</span>
      <button class="win-close">×</button>
    </div>
    <div class="window-body" style="display:flex; flex-direction:column; padding:0;">
      <div id="tabs"></div>
      <textarea id="editor"></textarea>
    </div>
  </div>
</div>

<script>
(function(){
  /* ---------- Window dragging ---------- */
  function makeDraggable(win){
    const bar = win.querySelector('.titlebar');
    let dragging=false, ox=0, oy=0;
    bar.addEventListener('mousedown', e=>{
      if(e.target.classList.contains('win-close')) return;
      dragging=true;
      ox = e.clientX - win.offsetLeft;
      oy = e.clientY - win.offsetTop;
      win.style.zIndex = 200;
    });
    document.addEventListener('mousemove', e=>{
      if(!dragging) return;
      win.style.left = (e.clientX - ox) + 'px';
      win.style.top = (e.clientY - oy) + 'px';
    });
    document.addEventListener('mouseup', ()=> dragging=false);
  }
  makeDraggable(document.getElementById('files-window'));
  makeDraggable(document.getElementById('notepad-window'));

  /* ---------- Launchers ---------- */
  document.getElementById('open-files').onclick = ()=>{
    document.getElementById('files-window').style.display='flex';
  };
  document.getElementById('open-notepad').onclick = ()=>{
    document.getElementById('notepad-window').style.display='flex';
    renderTabs();
    loadActiveTab();
  };
  document.querySelectorAll('.win-close').forEach(b=>{
    b.onclick = e=> e.target.closest('.window').style.display='none';
  });

  /* ---------- Files App ---------- */
  const fs = {
    '/': {type:'dir', children:['bin','etc','home','usr','var']},
    '/bin': {type:'dir', children:['bash','ls','cp']},
    '/etc': {type:'dir', children:['passwd','hosts','fstab']},
    '/home': {type:'dir', children:['user']},
    '/home/user': {type:'dir', children:['Documents','Downloads','Pictures','notes.txt','todo.md']},
    '/home/user/Documents': {type:'dir', children:['report.pdf','resume.docx']},
    '/home/user/Downloads': {type:'dir', children:['image.png','archive.zip']},
    '/home/user/Pictures': {type:'dir', children:['wallpaper.jpg','selfie.png']},
    '/usr': {type:'dir', children:['bin','lib','share']},
    '/var': {type:'dir', children:['log','www']}
  };
  let currentPath = '/';
  const pathEl = document.getElementById('files-path');
  const listEl = document.getElementById('files-list');

  function renderFiles(){
    pathEl.textContent = currentPath;
    listEl.innerHTML = '';
    const node = fs[currentPath];
    if(!node) return;
    node.children.forEach(name=>{
      const childPath = currentPath === '/' ? '/'+name : currentPath+'/'+name;
      const child = fs[childPath];
      const div = document.createElement('div');
      div.className = 'fs-item ' + (child && child.type==='dir' ? 'folder':'file');
      div.textContent = name;
      if(child && child.type==='dir'){
        div.ondblclick = ()=>{ currentPath = childPath; renderFiles(); };
      }
      listEl.appendChild(div);
    });
  }
  document.getElementById('files-up').onclick = ()=>{
    if(currentPath === '/') return;
    const parts = currentPath.split('/').filter(Boolean);
    parts.pop();
    currentPath = parts.length ? '/'+parts.join('/') : '/';
    renderFiles();
  };
  renderFiles();

  /* ---------- Notepad App ---------- */
  const LS_KEY = 'ubuntu_notepad_tabs';
  let tabs = JSON.parse(localStorage.getItem(LS_KEY) || '[{"id":1,"name":"Tab 1","content":""}]');
  let activeId = tabs.length ? tabs[0].id : null;

  const tabsEl = document.getElementById('tabs');
  const editor = document.getElementById('editor');
  const newTabBtn = document.getElementById('new-tab');

  function saveTabs(){
    localStorage.setItem(LS_KEY, JSON.stringify(tabs));
  }
  function renderTabs(){
    tabsEl.innerHTML = '';
    tabs.forEach(t=>{
      const el = document.createElement('div');
      el.className = 'tab' + (t.id===activeId?' active':'');
      el.textContent = t.name;
      el.onclick = ()=>{ activeId = t.id; renderTabs(); loadActiveTab(); };
      tabsEl.appendChild(el);
    });
    const btn = document.createElement('button');
    btn.id = 'new-tab';
    btn.textContent = '+';
    btn.onclick = ()=>{
      const id = Date.now();
      tabs.push({id, name:'Tab '+(tabs.length+1), content:''});
      activeId = id;
      saveTabs(); renderTabs(); loadActiveTab();
    };
    tabsEl.appendChild(btn);
  }
  function loadActiveTab(){
    const t = tabs.find(x=>x.id===activeId);
    editor.value = t ? t.content : '';
  }
  editor.addEventListener('input', ()=>{
    const t = tabs.find(x=>x.id===activeId);
    if(t){ t.content = editor.value; saveTabs(); }
  });
  // initial render (in case window opened before click)
  renderTabs();
  loadActiveTab();
})();
</script>
</body>
</html>
